import React from 'react';

const ResultPage = ({ result, teamInfo }) => {
  const { score, totalQuestions, timeTaken } = result;
  const percentage = (score / totalQuestions) * 100;

  const formatMicroseconds = (microseconds) => {
    const seconds = Math.floor(microseconds / 1_000_000);
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    const ms = Math.floor((microseconds % 1_000_000) / 1000);

    return `${minutes}m ${remainingSeconds}s ${ms}ms`;
  };

  const getScoreColor = () => {
    if (percentage >= 80) return '#48bb78';
    if (percentage >= 60) return '#ecc94b';
    return '#f56565';
  };

  const getScoreMessage = () => {
    if (percentage >= 80) return 'Excellent work!';
    if (percentage >= 60) return 'Good job!';
    if (percentage >= 40) return 'Keep practicing!';
    return 'Better luck next time!';
  };

  return (
    <div className="container">
      <div className="card">
        <h1>Quiz Complete!</h1>

        <div className="score-display">
          <div style={{ fontSize: '1.2rem', color: '#718096', marginBottom: '10px' }}>
            {teamInfo.teamName}
          </div>
          <div className="score-number" style={{ color: getScoreColor() }}>
            {score}/{totalQuestions}
          </div>
          <div className="score-label">
            {getScoreMessage()}
          </div>
        </div>

        <div className="time-details">
          <p>
            <strong>Time Taken:</strong>
          </p>
          <p className="microseconds">
            {formatMicroseconds(timeTaken)}
          </p>
          <p style={{ fontSize: '0.9rem', color: '#a0aec0', marginTop: '10px' }}>
            ({timeTaken.toLocaleString()} microseconds)
          </p>
        </div>

        <div style={{ textAlign: 'center', marginTop: '30px' }}>
          <button 
            className="btn"
            onClick={() => window.location.reload()}
          >
            Take Another Quiz
          </button>
        </div>

        <div style={{ marginTop: '20px', textAlign: 'center', color: '#718096', fontSize: '0.9rem' }}>
          <p>Thank you for participating!</p>
        </div>
      </div>
    </div>
  );
};

export default ResultPage;
